css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: 'Inter', sans-serif; background: #070b18; color: white; overflow-x: hidden; }

.navbar { display: flex; align-items: center; justify-content: space-between; padding: 0 80px; height: 80px; border-bottom: 1px solid rgba(255,255,255,0.08); position: sticky; top: 0; background: rgba(7,11,24,0.9); backdrop-filter: blur(20px); z-index: 100; }
.brand { font-size: 28px; font-weight: 900; } .brand span { color: #a855f7; }
.nav-links { display: flex; gap: 32px; } .nav-links a { color: #94a3b8; text-decoration: none; font-weight: 500; transition: color 0.2s; } .nav-links a:hover { color: white; }
.nav-btn { border: none; padding: 12px 24px; border-radius: 12px; background: linear-gradient(135deg, #a855f7, #ec4899); color: white; font-weight: 700; cursor: pointer; }

.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 80px; min-height: calc(100vh - 80px); }
.badge { display: inline-block; padding: 8px 16px; border-radius: 20px; background: rgba(168,85,247,0.15); border: 1px solid rgba(168,85,247,0.3); color: #a855f7; font-size: 13px; font-weight: 700; margin-bottom: 24px; }
h1 { font-size: 64px; font-weight: 900; line-height: 1.05; letter-spacing: -2px; margin-bottom: 24px; } h1 span { background: linear-gradient(135deg, #a855f7, #ec4899); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.hero-left p { font-size: 18px; color: #94a3b8; line-height: 1.7; margin-bottom: 36px; max-width: 480px; }
.hero-actions { display: flex; gap: 16px; margin-bottom: 48px; }
.btn-primary { padding: 16px 32px; border-radius: 14px; border: none; background: linear-gradient(135deg, #a855f7, #ec4899); color: white; font-size: 16px; font-weight: 700; cursor: pointer; box-shadow: 0 20px 40px rgba(168,85,247,0.35); transition: transform 0.2s; } .btn-primary:hover { transform: translateY(-2px); }
.btn-secondary { padding: 16px 32px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.2); background: rgba(255,255,255,0.06); color: white; font-size: 16px; font-weight: 600; cursor: pointer; }
.hero-stats { display: flex; gap: 32px; } .stat strong { display: block; font-size: 28px; font-weight: 900; } .stat span { color: #64748b; font-size: 13px; }

.hero-card { background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.12); border-radius: 24px; padding: 24px; position: relative; }
.card-header { display: flex; align-items: center; gap: 12px; margin-bottom: 24px; }
.dots { display: flex; gap: 6px; } .dots span { width: 10px; height: 10px; border-radius: 50%; background: rgba(255,255,255,0.2); }
.card-title { font-size: 13px; font-weight: 600; color: #94a3b8; }
.card-chart { display: flex; align-items: end; gap: 8px; height: 100px; margin-bottom: 24px; }
.bar { flex: 1; border-radius: 6px; background: linear-gradient(180deg, #a855f7, #ec4899); }
.card-stats { display: flex; justify-content: space-between; } .card-stats div { text-align: center; } .card-stats strong { display: block; font-size: 18px; font-weight: 800; } .card-stats small { color: #64748b; font-size: 12px; }
.floating-badge { position: absolute; bottom: -16px; right: 24px; background: #22c55e; color: white; padding: 8px 16px; border-radius: 20px; font-size: 13px; font-weight: 700; }

.features { padding: 80px; } .features h2 { font-size: 42px; font-weight: 800; text-align: center; margin-bottom: 48px; }
.features-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 24px; }
.feature-card { padding: 32px; border-radius: 20px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); transition: transform 0.2s; } .feature-card:hover { transform: translateY(-4px); }
.feature-icon { font-size: 36px; margin-bottom: 16px; } .feature-card h3 { font-size: 18px; font-weight: 700; margin-bottom: 8px; } .feature-card p { color: #64748b; line-height: 1.6; }

js:
document.querySelectorAll('.btn-primary, .btn-secondary, .nav-btn').forEach(btn => { btn.addEventListener('mouseenter', function() { this.style.opacity = '0.9'; }); btn.addEventListener('mouseleave', function() { this.style.opacity = '1'; }); });

const observer = new IntersectionObserver((entries) => { entries.forEach(e => { if (e.isIntersecting) { e.target.style.opacity = '1'; e.target.style.transform = 'translateY(0)'; } }); }, { threshold: 0.1 });
document.querySelectorAll('.feature-card').forEach(card => { card.style.opacity = '0'; card.style.transform = 'translateY(20px)'; card.style.transition = 'opacity 0.5s, transform 0.5s'; observer.observe(card); });
